import { PriorityQueue } from 'typescript-collections';

function solve(m, n, waitCost) {
    const directions = [[0, 1], [1, 0]]; // Right, Down

    // Priority queue: (totalCost, time, i, j)
    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([1, 0, 0, 0]); // Start at (0,0) with time 0 and cost 1

    // Visited dictionary to keep track of the minimum cost to reach each cell at a certain time
    const visited = new Map();

    while (!pq.isEmpty()) {
        const [totalCost, time, i, j] = pq.dequeue();

        // If we reach the destination, return the total cost
        if (i === m - 1 && j === n - 1) {
            return totalCost;
        }

        // Skip if we have already found a better path to this cell at this time
        const key = `${i},${j},${time}`;
        if (visited.has(key) && visited.get(key) <= totalCost) {
            continue;
        }

        visited.set(key, totalCost);

        // Check if it's an odd or even second
        if (time % 2 === 0) {
            // Even second: must wait in place
            const waitCostVal = waitCost[i][j];
            const newTotalCost = totalCost + waitCostVal;
            pq.enqueue([newTotalCost, time + 1, i, j]);
        } else {
            // Odd second: must move right or down
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    // Enter cost is (i+1)*(j+1) for the new cell
                    const enterCost = (ni + 1) * (nj + 1);
                    const newTotalCost = totalCost + enterCost;
                    pq.enqueue([newTotalCost, time + 1, ni, nj]);
                }
            }
        }
    }

    // If no path is found (should not happen in valid inputs)
    return -1;
}
